if (! function_exists('mongodb_query')) {
    function mongodb_query($operation, $host = null, $port = null, $database = null, $collection = null, $username = null, $password = null, $filter = null, $document = null, $documents = null, $update = null, $pipeline = null, $limit = null, $sort = null, $skip = null, $timeout = null)
    {
        // MongoDB client using the MongoDB PHP extension
        // Supports document database CRUD and aggregation operations

        // Validate inputs
        $host = isset($host) ? (string)$host : '127.0.0.1';
        $port = isset($port) ? (int)$port : 27017;
        $database = isset($database) ? (string)$database : '';
        $collection = isset($collection) ? (string)$collection : '';
        $username = isset($username) ? (string)$username : '';
        $password = isset($password) ? (string)$password : '';
        $operation = isset($operation) ? (string)$operation : 'find';
        $limit = isset($limit) ? max(0, (int)$limit) : 50;
        $skip = isset($skip) ? max(0, (int)$skip) : 0;
        $timeout = isset($timeout) ? min(max((int)$timeout, 1), 60) : 10;

        // Parse JSON parameters
        $filter = [];
        if (isset($filter) && is_string($filter) && $filter !== '') {
            $parsed = json_decode($filter, true);
            if ($parsed === null && json_last_error() !== JSON_ERROR_NONE) {
                return ['error' => 'Invalid filter JSON: ' . json_last_error_msg(), 'result' => null];
            }
            $filter = $parsed ?: [];
        }

        $update_doc = [];
        if (isset($update) && is_string($update) && $update !== '') {
            $parsed = json_decode($update, true);
            if ($parsed === null && json_last_error() !== JSON_ERROR_NONE) {
                return ['error' => 'Invalid update JSON: ' . json_last_error_msg(), 'result' => null];
            }
            $update_doc = $parsed ?: [];
        }

        $sort_doc = [];
        if (isset($sort) && is_string($sort) && $sort !== '') {
            $parsed = json_decode($sort, true);
            if ($parsed === null && json_last_error() !== JSON_ERROR_NONE) {
                return ['error' => 'Invalid sort JSON: ' . json_last_error_msg(), 'result' => null];
            }
            $sort_doc = $parsed ?: [];
        }

        // Check if MongoDB extension is available
        if (!extension_loaded('mongodb')) {
            return ['error' => 'MongoDB PHP extension is not loaded', 'result' => null];
        }

        try {
            // Build connection URI
            $uri = 'mongodb://';
            if ($username !== '' && $password !== '') {
                $uri .= urlencode($username) . ':' . urlencode($password) . '@';
            }
            $uri .= "{$host}:{$port}";
            $uri .= '/?connectTimeoutMS=' . ($timeout * 1000) . '&serverSelectionTimeoutMS=' . ($timeout * 1000);
            
            $manager = new MongoDB\Driver\Manager($uri);
            
            $result_data = null;
            
            switch ($operation) {
                case 'list_databases':
                    $cmd = new MongoDB\Driver\Command(['listDatabases' => 1]);
                    $cursor = $manager->executeCommand('admin', $cmd);
                    $dbs = $cursor->toArray()[0] ?? null;
                    if ($dbs && isset($dbs->databases)) {
                        $result_data = [];
                        foreach ($dbs->databases as $db) {
                            $result_data[] = [
                                'name' => $db->name,
                                'size_on_disk' => $db->sizeOnDisk ?? 0,
                                'empty' => $db->empty ?? false,
                            ];
                        }
                    }
                    break;
                    
                case 'list_collections':
                    if ($database === '') {
                        return ['error' => 'Database name required for list_collections', 'result' => null];
                    }
                    $cmd = new MongoDB\Driver\Command(['listCollections' => 1]);
                    $cursor = $manager->executeCommand($database, $cmd);
                    $result_data = [];
                    foreach ($cursor as $col) {
                        $result_data[] = [
                            'name' => $col->name,
                            'type' => $col->type ?? 'collection',
                        ];
                    }
                    break;
                    
                case 'create_collection':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for create_collection', 'result' => null];
                    }
                    $cmd = new MongoDB\Driver\Command(['create' => $collection]);
                    $cursor = $manager->executeCommand($database, $cmd);
                    $result_data = $cursor->toArray();
                    break;
                    
                case 'drop_collection':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for drop_collection', 'result' => null];
                    }
                    $cmd = new MongoDB\Driver\Command(['drop' => $collection]);
                    $cursor = $manager->executeCommand($database, $cmd);
                    $result_data = 'Collection dropped (if existed)';
                    break;
                    
                case 'drop_database':
                    if ($database === '') {
                        return ['error' => 'Database name required for drop_database', 'result' => null];
                    }
                    $cmd = new MongoDB\Driver\Command(['dropDatabase' => 1]);
                    $cursor = $manager->executeCommand($database, $cmd);
                    $result_data = 'Database dropped';
                    break;
                    
                case 'find':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for find', 'result' => null];
                    }
                    $query = new MongoDB\Driver\Query($filter, [
                        'sort' => $sort_doc ?: null,
                        'limit' => $limit > 0 ? $limit : 0,
                        'skip' => $skip,
                    ]);
                    $cursor = $manager->executeQuery("{$database}.{$collection}", $query);
                    $docs = [];
                    foreach ($cursor as $doc) {
                        $docs[] = json_decode(json_encode($doc), true);
                    }
                    $result_data = [
                        'count' => count($docs),
                        'documents' => $docs
                    ];
                    break;
                    
                case 'find_one':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for find_one', 'result' => null];
                    }
                    $query = new MongoDB\Driver\Query($filter, ['limit' => 1]);
                    $cursor = $manager->executeQuery("{$database}.{$collection}", $query);
                    $doc = null;
                    foreach ($cursor as $d) {
                        $doc = json_decode(json_encode($d), true);
                        break;
                    }
                    $result_data = $doc;
                    break;
                    
                case 'insert_one':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for insert_one', 'result' => null];
                    }
                    $doc = [];
                    if (isset($document) && is_string($document) && $document !== '') {
                        $doc = json_decode($document, true);
                        if ($doc === null) {
                            return ['error' => 'Invalid document JSON: ' . json_last_error_msg(), 'result' => null];
                        }
                    } else {
                        return ['error' => 'Document parameter required for insert_one', 'result' => null];
                    }
                    $bulk = new MongoDB\Driver\BulkWrite();
                    $oid = $bulk->insert($doc);
                    $result = $manager->executeBulkWrite("{$database}.{$collection}", $bulk);
                    $result_data = [
                        'inserted_count' => $result->getInsertedCount(),
                        'inserted_id' => (string)$oid,
                    ];
                    break;
                    
                case 'insert_many':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for insert_many', 'result' => null];
                    }
                    $docs = [];
                    if (isset($documents) && is_string($documents) && $documents !== '') {
                        $docs = json_decode($documents, true);
                        if (!is_array($docs)) {
                            return ['error' => 'Documents must be a JSON array', 'result' => null];
                        }
                    } else {
                        return ['error' => 'Documents parameter required for insert_many', 'result' => null];
                    }
                    $bulk = new MongoDB\Driver\BulkWrite();
                    foreach ($docs as $doc) {
                        $bulk->insert($doc);
                    }
                    $result = $manager->executeBulkWrite("{$database}.{$collection}", $bulk);
                    $result_data = [
                        'inserted_count' => $result->getInsertedCount(),
                    ];
                    break;
                    
                case 'update_one':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for update_one', 'result' => null];
                    }
                    if (empty($update_doc)) {
                        return ['error' => 'Update document required for update operations', 'result' => null];
                    }
                    $bulk = new MongoDB\Driver\BulkWrite();
                    $bulk->update($filter, $update_doc, ['multi' => false]);
                    $result = $manager->executeBulkWrite("{$database}.{$collection}", $bulk);
                    $result_data = [
                        'matched_count' => $result->getMatchedCount(),
                        'modified_count' => $result->getModifiedCount(),
                    ];
                    break;
                    
                case 'update_many':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for update_many', 'result' => null];
                    }
                    if (empty($update_doc)) {
                        return ['error' => 'Update document required for update operations', 'result' => null];
                    }
                    $bulk = new MongoDB\Driver\BulkWrite();
                    $bulk->update($filter, $update_doc, ['multi' => true]);
                    $result = $manager->executeBulkWrite("{$database}.{$collection}", $bulk);
                    $result_data = [
                        'matched_count' => $result->getMatchedCount(),
                        'modified_count' => $result->getModifiedCount(),
                    ];
                    break;
                    
                case 'delete_one':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for delete_one', 'result' => null];
                    }
                    $bulk = new MongoDB\Driver\BulkWrite();
                    $bulk->delete($filter, ['limit' => 1]);
                    $result = $manager->executeBulkWrite("{$database}.{$collection}", $bulk);
                    $result_data = [
                        'deleted_count' => $result->getDeletedCount(),
                    ];
                    break;
                    
                case 'delete_many':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for delete_many', 'result' => null];
                    }
                    $bulk = new MongoDB\Driver\BulkWrite();
                    $bulk->delete($filter, ['limit' => 0]);
                    $result = $manager->executeBulkWrite("{$database}.{$collection}", $bulk);
                    $result_data = [
                        'deleted_count' => $result->getDeletedCount(),
                    ];
                    break;
                    
                case 'count':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for count', 'result' => null];
                    }
                    $cmd = new MongoDB\Driver\Command([
                        'count' => $collection,
                        'query' => $filter,
                    ]);
                    $cursor = $manager->executeCommand($database, $cmd);
                    $result_data = $cursor->toArray()[0]->n ?? 0;
                    break;
                    
                case 'aggregate':
                    if ($database === '' || $collection === '') {
                        return ['error' => 'Database and collection required for aggregate', 'result' => null];
                    }
                    $pipeline_docs = [];
                    if (isset($pipeline) && is_string($pipeline) && $pipeline !== '') {
                        $pipeline_docs = json_decode($pipeline, true);
                        if (!is_array($pipeline_docs)) {
                            return ['error' => 'Pipeline must be a JSON array of stage objects', 'result' => null];
                        }
                    } else {
                        return ['error' => 'Pipeline parameter required for aggregate', 'result' => null];
                    }
                    $cmd = new MongoDB\Driver\Command([
                        'aggregate' => $collection,
                        'pipeline' => $pipeline_docs,
                        'cursor' => new stdClass(),
                    ]);
                    $cursor = $manager->executeCommand($database, $cmd);
                    $docs = [];
                    foreach ($cursor as $doc) {
                        $docs[] = json_decode(json_encode($doc), true);
                    }
                    $result_data = [
                        'count' => count($docs),
                        'results' => $docs
                    ];
                    break;
                    
                default:
                    return ['error' => "Unknown operation: {$operation}", 'result' => null];
            }
            
            return [
                'success' => true,
                'server' => "{$host}:{$port}",
                'database' => $database ?: '(admin)',
                'collection' => $collection ?: '(none)',
                'operation' => $operation,
                'result' => $result_data,
            ];
            
        } catch (\MongoDB\Driver\Exception\AuthenticationException $e) {
            return ['error' => 'MongoDB authentication failed: ' . $e->getMessage(), 'result' => null];
        } catch (\MongoDB\Driver\Exception\ConnectionTimeoutException $e) {
            return ['error' => 'MongoDB connection timeout: ' . $e->getMessage(), 'result' => null];
        } catch (\MongoDB\Driver\Exception\BulkWriteException $e) {
            $writeResult = $e->getWriteResult();
            $writeErrors = $writeResult ? $writeResult->getWriteErrors() : [];
            $details = [];
            foreach ($writeErrors as $we) {
                $details[] = $we->getMessage();
            }
            return [
                'error' => 'MongoDB write error: ' . $e->getMessage(),
                'write_errors' => $details,
                'result' => null
            ];
        } catch (\Throwable $e) {
            // Handle gracefully - MongoDB extension might connect but operations fail
            $msg = $e->getMessage();
            // Check for "No suitable servers" (no MongoDB running)
            if (str_contains($msg, 'No suitable servers') || str_contains($msg, 'Connection refused')) {
                return [
                    'error' => 'MongoDB server not available',
                    'details' => "Could not connect to {$host}:{$port}. No MongoDB server running.",
                    'result' => null
                ];
            }
            return ['error' => 'MongoDB error: ' . $msg, 'result' => null];
